import { ProjectHookRuntime } from '../app/hooks/runtime.js';
import { scanEmitterDefs } from './emitter-manifests.js';
import { WebRenderHost } from '../rpc/server.js';
import { TraceHub } from '../rpc/trace-hub.js';
import {
  DEFAULT_PROJECT_ID,
  SYSTEM_PROJECT_ID,
  safeProjectId,
  slugify,
  scaffoldProject,
